import warnings
import functools

def deprecate(arg=None, *, message=None, category=DeprecationWarning):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            final_message = message if message is not None else \
                            f"Call to deprecated function {func.__name__}."
            warnings.warn(
                final_message,
                category=category,
                stacklevel=2
            )
            return func(*args, **kwargs)
        return wrapper

    if callable(arg):
        return decorator(arg)
    else:
        if arg is not None:
            message = arg
        return decorator
